import{mostrarResultado}from"../../renderResult.js";export function render(t){const{accion:n,clientes:o,mensaje:e}=t.respuesta;if("listar"!==n&&n)mostrarResultado(`<p>${e}</p>\n            <button onclick="sendPrompt('accion=listar')">← Volver al listado</button>`);else{const t=o.map(t=>`\n            <tr>\n                <td>${t.id}</td>\n                <td>${t.nombre}</td>\n                <td>${t.dni}</td>\n                <td>${t.direccion}</td>\n                <td>\n                    <button onclick="sendPrompt('accion=modificar&id=${t.id}')">✏️ Editar</button>\n                    <button onclick="sendPrompt('accion=baja&id=${t.id}')">🗑 Eliminar</button>\n                </td>\n            </tr>\n        `).join("");mostrarResultado(`\n            <button onclick="sendPrompt('accion=alta')">+ Nuevo cliente</button>\n            <h3>Listado de clientes</h3>\n            <table border="1">\n                <thead><tr><th>ID</th><th>Nombre</th><th>DNI</th><th>Dirección</th><th>Acciones</th></tr></thead>\n                <tbody>${t}</tbody>\n            </table>\n        `)}}//# sourceMappingURL=ejercicio1.js.map
